ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE attachment {
  low: { SELECT ?title WHERE {
  ?projects a :Projects .
  ?projects p:title ?title .
  ?projects p:researchMethod ?researchmethod_w .
  ?projects p:researchMethod ?researchmethod_w2 .
  ?projects p:topic ?topic_w .
  FILTER((STR(?researchmethod_w) = "Case Study" || (STR(?researchmethod_w2) = "Interview" && STR(?topic_w) = "Environmental Science")))
} }
  high: { SELECT ?title WHERE {
  ?projects a :Projects .
  ?projects p:title ?title .
  ?projects p:researchMethod ?researchmethod_w .
  ?projects p:researchMethod ?researchmethod_w2 .
  ?projects p:topic ?topic_w .
  FILTER((((STR(?researchmethod_w) = "Case Study" || STR(?researchmethod_w2) = "Interview")) && STR(?topic_w) = "Environmental Science"))
} }
}
